(7, 'Hôtel Ritz Paris', 'Historic palace hotel in central Paris offering timeless elegance and luxury suites.', '15 Place Vendôme, Paris, France', 105, '75001', '2026-04-22 05:23:19', '2026-04-22 05:38:08', 0.00, 3),
(8, 'The Beverly Hills Hotel', 'Legendary luxury hotel in Los Angeles known for Hollywood glamour and premium hospitality.', '9641 Sunset Blvd, Beverly Hills, CA', 84, '90210', '2026-04-22 05:23:19', '2026-04-22 06:00:54', 10.00, 3),
(9, 'The Ritz-Carlton Riyadh', 'Grand luxury hotel featuring palatial architecture and premium services in Saudi Arabia.', 'Al Hada Area, Riyadh, Saudi Arabia', 141, '11493', '2026-04-22 05:23:19', '2026-04-27 04:49:41', 5.00, 3),
(10, 'Jeddah Hilton', 'Modern waterfront hotel offering Red Sea views and premium accommodations in Jeddah.', 'North Corniche Rd, Jeddah, Saudi Arabia', 143, '23511', '2026-04-22 05:23:19', '2026-04-22 06:01:02', 18.00, 3),
(11, 'Hotel The Grand Regency', 'A modern hotel in the heart of Rajkot offering comfortable rooms, fast WiFi, and in-house dining. Ideal for both business and leisure stays with easy access to major city attractions.', 'Dr. Yagnik Road, Near Race Course Ring Road', 27, '360001', '2026-04-22 05:42:22', '2026-04-22 05:42:22', 0.00, 3);
